Here's a modern MSTest 3.x test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, HttpClient client) CreateFetcher(HttpMessageHandler handler)
    {
        var client = new HttpClient(handler);
        return (new DataFetcher(client), client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.NotFound,
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage(System.Net.HttpStatusCode.OK),
            simulateDelay: TimeSpan.FromSeconds(30));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;
        using var cts = new CancellationTokenSource();

        // Act & Assert
        cts.Cancel(); // cancel immediately
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // test-level timeout — enforced via TestContext.CancellationToken
    public async Task FetchAsync_SlowServer_TimeoutCancelsOperation()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage(System.Net.HttpStatusCode.OK),
            simulateDelay: TimeSpan.FromSeconds(60));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert — the [Timeout] fires CancellationToken, which cancels GetAsync
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    /// <summary>Minimal HttpMessageHandler that returns a canned response.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response, TimeSpan simulateDelay = default)
        {
            _response = response;
            _delay = simulateDelay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken); // throws if cancelled
            }

            return _response;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `_testContext.CancellationToken` | Cooperates with `[Timeout]` — MSTest cancels this token when time expires |
| `Assert.ThrowsExactlyAsync<T>` | Catches the exact exception type, replaces `[ExpectedException]` |
| `Assert.ThrowsAsync<T>` | Used for timeout test since `HttpClient` may throw `TaskCanceledException` or a derived type |
| `FakeHandler` | Avoids real HTTP calls; controls delays for cancellation/timeout tests |
| `sealed` class + `sealed` handler | Performance and design clarity |
| `[Timeout(N)]` on each async test | Prevents hung tests; the token auto-cancels when time runs out |

The critical insight: **`[Timeout]` alone doesn't kill your code** — you must pass `TestContext.CancellationToken` into async calls so MSTest can cooperatively cancel them when the timeout fires.
